// src/audit/audit.interceptor.spec.ts
import { Test, TestingModule } from '@nestjs/testing';
import { ExecutionContext, CallHandler } from '@nestjs/common';
import { of, Observable } from 'rxjs';
import { Reflector } from '@nestjs/core';
import { AuditInterceptor } from './audit.interceptor';
import { AuditService } from './audit.service';
import { AuditSeverity, AuditSource } from '@prisma/client';

describe('AuditInterceptor', () => {
  let interceptor: AuditInterceptor;
  let reflector: Reflector;
  let auditService: jest.Mocked<AuditService>;

  const mockAuditMeta = {
    action: 'CREATE',
    entityType: 'User',
    severity: AuditSeverity.INFO,
    source: AuditSource.USER,
  };

  const mockUser = {
    userId: 1,
    email: 'test@example.com',
    role: 'ADMIN',
  };

  const createMockExecutionContext = (overrides: {
    user?: object;
    ip?: string;
    headers?: Record<string, string>;
    statusCode?: number;
  } = {}) => {
    return {
      switchToHttp: jest.fn().mockReturnValue({
        getRequest: jest.fn().mockReturnValue({
          ip: overrides.ip || '127.0.0.1',
          headers: overrides.headers || { 'user-agent': 'Test' },
          user: overrides.user,
        }),
        getResponse: jest.fn().mockReturnValue({ 
          statusCode: overrides.statusCode || 200 
        }),
      }),
      getHandler: jest.fn(),
    } as unknown as ExecutionContext;
  };

  const createMockCallHandler = (response: object = { id: 123 }): CallHandler => {
    return {
      handle: jest.fn().mockReturnValue(of(response)),
    } as unknown as CallHandler;
  };

  beforeEach(async () => {
    const mockRecordFn = jest.fn().mockResolvedValue(undefined);

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AuditInterceptor,
        {
          provide: Reflector,
          useValue: {
            get: jest.fn().mockImplementation((key: string, defaultValue?: unknown) => {
              // Return the mock audit meta for 'audit' key
              if (key === 'audit') {
                return mockAuditMeta;
              }
              return defaultValue;
            }),
          },
        },
        {
          provide: AuditService,
          useValue: {
            record: mockRecordFn,
          },
        },
      ],
    }).compile();

    interceptor = module.get<AuditInterceptor>(AuditInterceptor);
    reflector = module.get<Reflector>(Reflector);
    auditService = module.get(AuditService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('intercept', () => {
    it('should not audit when no audit metadata is present', async () => {
      // Override the Reflector to return undefined for this specific test
      (reflector.get as jest.Mock).mockImplementation((key: string) => {
        if (key === 'audit') {
          return undefined;
        }
        return undefined;
      });
      
      const mockExecutionContext = createMockExecutionContext({ user: mockUser });
      const mockCallHandler = createMockCallHandler();

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      expect(auditService.record).not.toHaveBeenCalled();
    });

    it('should create audit entry with correct metadata', async () => {
      const mockExecutionContext = createMockExecutionContext({ 
        user: mockUser,
        ip: '127.0.0.1',
        headers: { 'user-agent': 'Mozilla/5.0' },
      });
      const mockCallHandler = createMockCallHandler({ id: 123, name: 'Test' });

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      expect(auditService.record).toHaveBeenCalledWith(
        expect.objectContaining({
          action: 'CREATE',
          entityType: 'User',
          severity: AuditSeverity.INFO,
          source: AuditSource.USER,
          actorId: 1,
          actorEmail: 'test@example.com',
        }),
      );
    });

    it('should handle missing user gracefully', async () => {
      const mockExecutionContext = createMockExecutionContext({ 
        user: undefined,
        ip: '127.0.0.1',
        headers: { 'user-agent': 'Test' },
      });
      const mockCallHandler = createMockCallHandler({ id: 123 });

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      expect(auditService.record).toHaveBeenCalledWith(
        expect.objectContaining({
          actorId: undefined,
          actorEmail: undefined,
        }),
      );
    });

    it('should handle missing IP gracefully', async () => {
      const mockExecutionContext = createMockExecutionContext({ 
        user: mockUser,
        headers: { 'user-agent': 'Test' },
      });
      const mockCallHandler = createMockCallHandler({ id: 123 });

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      expect(auditService.record).toHaveBeenCalled();
    });

    it('should not throw when auditService.record fails', async () => {
      (auditService.record as jest.Mock).mockRejectedValueOnce(
        new Error('Database error'),
      );
      
      const mockExecutionContext = createMockExecutionContext({ 
        user: mockUser,
      });
      const mockCallHandler = createMockCallHandler({ id: 123 });

      // Should not throw - the interceptor catches errors from record()
      await expect(
        interceptor.intercept(mockExecutionContext, mockCallHandler),
      ).toBeDefined();
    });

    it('should capture response data after handler executes', async () => {
      const mockResponse = { id: 123, name: 'Test User' };
      const mockExecutionContext = createMockExecutionContext({ 
        user: mockUser,
      });
      const mockCallHandler = createMockCallHandler(mockResponse);

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      // Verify handle was called
      expect(mockCallHandler.handle).toHaveBeenCalled();
      
      // Verify auditService.record was called with response data
      expect(auditService.record).toHaveBeenCalledWith(
        expect.objectContaining({
          newValue: mockResponse,
        }),
      );
    });
  });
});
